const scenesUrl = $input.item.json.output_files.out_scenes.storage_url;
const sourceVideoUrl = $input.item.json.output_files.out_video.storage_url;
const raw = await this.helpers.httpRequest({ method: 'GET', url: scenesUrl, returnFullResponse: false });
const text = typeof raw === 'string' ? raw : JSON.stringify(raw);
const minS = 1;
const maxS = 6;
const times = [];
const re = /pts_time:([0-9]+\.?[0-9]*)/g;
let m;
while ((m = re.exec(text)) !== null) times.push(parseFloat(m[1]));
let hookEnd, reason;
if (times.length === 0) { hookEnd = maxS; reason = 'no_scene_cut_fallback_to_max'; }
else {
  const first = times[0];
  if (first < minS) {
    const next = times.find(t => t >= minS);
    hookEnd = next != null ? Math.min(next, maxS) : maxS;
    reason = next != null ? 'first_cut_too_early_used_next' : 'first_cut_too_early_used_max';
  } else {
    hookEnd = Math.min(first, maxS);
    reason = first <= maxS ? 'first_scene_cut' : 'first_cut_above_max_capped';
  }
}
const hookEndSec = Math.round(hookEnd * 1000) / 1000;
return { json: { hookEndSec, allSceneCuts: times, reason, sourceVideoUrl } };
